// Ten-pin bowling scoring engine.
// A frame holds the rolls (pin counts) thrown in that frame.
// Standard frames (1-9): 1 or 2 rolls. 10th frame: up to 3 rolls.
//
// This module is pure: feed it rolls, ask it for frame scores. No rendering.

export const TOTAL_FRAMES = 10;
export const PINS = 10;

export function createGame() {
  return {
    frames: Array.from({ length: TOTAL_FRAMES }, () => ({ rolls: [] })),
    currentFrame: 0, // 0-indexed
    over: false,
  };
}

// How many pins are standing at the start of the current ball within a frame.
// Returns the number of pins available to knock down for the *next* roll.
export function pinsAvailable(game) {
  const frame = game.frames[game.currentFrame];
  const isTenth = game.currentFrame === TOTAL_FRAMES - 1;
  const rolls = frame.rolls;

  if (!isTenth) {
    // Frames 1-9: after a strike the frame is done; otherwise 10 - first ball.
    if (rolls.length === 0) return PINS;
    return PINS - rolls[0];
  }

  // 10th frame logic.
  if (rolls.length === 0) return PINS;
  if (rolls.length === 1) {
    if (rolls[0] === PINS) return PINS; // strike -> fresh rack
    return PINS - rolls[0];
  }
  if (rolls.length === 2) {
    const sum = rolls[0] + rolls[1];
    if (rolls[0] === PINS) {
      // first was a strike; second ball was on a fresh rack
      return rolls[1] === PINS ? PINS : PINS - rolls[1];
    }
    if (sum === PINS) return PINS; // spare -> fresh rack for bonus ball
    return 0; // open frame, no third ball
  }
  return 0;
}

// Whether the player gets another ball in the current frame after this roll.
function frameContinues(game) {
  const frame = game.frames[game.currentFrame];
  const isTenth = game.currentFrame === TOTAL_FRAMES - 1;
  const rolls = frame.rolls;

  if (!isTenth) {
    if (rolls.length === 0) return true;
    if (rolls.length === 1) return rolls[0] < PINS; // strike ends frame early
    return false;
  }

  // 10th frame: you get a 3rd ball only with a strike or spare in first two.
  if (rolls.length === 1) return true;
  if (rolls.length === 2) {
    const earnedThird = rolls[0] === PINS || rolls[0] + rolls[1] === PINS;
    return earnedThird;
  }
  return false;
}

// Record a roll of `pins` knocked down. Returns an event describing what happened.
export function roll(game, pins) {
  if (game.over) return { type: "gameOver" };
  const frame = game.frames[game.currentFrame];
  frame.rolls.push(pins);

  const continues = frameContinues(game);
  if (continues) {
    return { type: "nextBall", frame: game.currentFrame };
  }

  // Frame complete; advance.
  if (game.currentFrame === TOTAL_FRAMES - 1) {
    game.over = true;
    return { type: "gameOver" };
  }
  game.currentFrame += 1;
  return { type: "nextFrame", frame: game.currentFrame };
}

// Flatten all rolls across frames in throw order (for bonus lookahead).
function flatRolls(game) {
  const flat = [];
  game.frames.forEach((f, fi) => {
    f.rolls.forEach((r, ri) => flat.push({ pins: r, frame: fi, idx: ri }));
  });
  return flat;
}

// Cumulative score per frame. Unscorable frames (waiting on bonus balls) are null.
export function frameScores(game) {
  const scores = new Array(TOTAL_FRAMES).fill(null);
  const flat = flatRolls(game);

  // Build a per-frame mapping of where its rolls start in the flat list.
  const frameStart = [];
  let cursor = 0;
  for (let f = 0; f < TOTAL_FRAMES; f++) {
    frameStart[f] = cursor;
    cursor += game.frames[f].rolls.length;
  }

  let running = 0;
  for (let f = 0; f < TOTAL_FRAMES; f++) {
    const rolls = game.frames[f].rolls;
    if (rolls.length === 0) break;
    const start = frameStart[f];

    let frameTotal = null;

    if (f < TOTAL_FRAMES - 1) {
      const isStrike = rolls[0] === PINS;
      const isSpare = !isStrike && rolls.length >= 2 && rolls[0] + rolls[1] === PINS;

      if (isStrike) {
        // need next two rolls
        const b1 = flat[start + 1];
        const b2 = flat[start + 2];
        if (b1 && b2) frameTotal = PINS + b1.pins + b2.pins;
      } else if (isSpare) {
        const b1 = flat[start + 2];
        if (b1) frameTotal = PINS + b1.pins;
      } else if (rolls.length >= 2) {
        frameTotal = rolls[0] + rolls[1];
      }
    } else {
      // 10th frame: just sum its own rolls once it's complete.
      const complete = isTenthComplete(rolls);
      if (complete) frameTotal = rolls.reduce((a, b) => a + b, 0);
    }

    if (frameTotal === null) {
      // can't score this frame yet; nothing after it can be scored either
      break;
    }
    running += frameTotal;
    scores[f] = running;
  }

  return scores;
}

function isTenthComplete(rolls) {
  if (rolls.length < 2) return false;
  const earnedThird = rolls[0] === PINS || rolls[0] + rolls[1] === PINS;
  if (earnedThird) return rolls.length === 3;
  return rolls.length === 2;
}

export function totalScore(game) {
  const scores = frameScores(game);
  for (let i = scores.length - 1; i >= 0; i--) {
    if (scores[i] !== null) return scores[i];
  }
  return 0;
}

// Symbol for a given roll in a given frame, for the scoreboard cells (X, /, -, n).
export function rollSymbol(game, frameIdx, rollIdx) {
  const rolls = game.frames[frameIdx].rolls;
  if (rollIdx >= rolls.length) return "";
  const pins = rolls[rollIdx];
  const isTenth = frameIdx === TOTAL_FRAMES - 1;

  if (!isTenth) {
    if (rollIdx === 0) {
      if (pins === PINS) return "X";
      return pins === 0 ? "-" : String(pins);
    }
    // second roll
    if (rolls[0] + pins === PINS) return "/";
    return pins === 0 ? "-" : String(pins);
  }

  // 10th frame symbols
  if (rollIdx === 0) {
    if (pins === PINS) return "X";
    return pins === 0 ? "-" : String(pins);
  }
  if (rollIdx === 1) {
    if (rolls[0] === PINS) {
      // fresh rack
      if (pins === PINS) return "X";
      return pins === 0 ? "-" : String(pins);
    }
    if (rolls[0] + pins === PINS) return "/";
    return pins === 0 ? "-" : String(pins);
  }
  // rollIdx === 2
  if (pins === PINS) return "X";
  // could be a spare on bonus balls
  if (rolls[1] !== PINS && rolls[0] !== PINS && false) return "";
  // if second ball wasn't a strike and first two on fresh rack formed a spare
  if (rolls[0] === PINS && rolls[1] !== PINS && rolls[1] + pins === PINS) return "/";
  return pins === 0 ? "-" : String(pins);
}

// Plain Node test for the scoring engine. Run: node js/scoring.test.mjs
import { createGame, roll, totalScore, frameScores, rollSymbol } from "./scoring.js";

let pass = 0, fail = 0;
function check(name, got, want) {
  const ok = JSON.stringify(got) === JSON.stringify(want);
  if (ok) { pass++; }
  else { fail++; console.error(`FAIL ${name}: got ${JSON.stringify(got)} want ${JSON.stringify(want)}`); }
}

function rollMany(g, arr) { for (const p of arr) roll(g, p); return g; }

// Gutter game = 0
{
  const g = createGame();
  rollMany(g, new Array(20).fill(0));
  check("gutter total", totalScore(g), 0);
}

// All ones = 20
{
  const g = createGame();
  rollMany(g, new Array(20).fill(1));
  check("all ones", totalScore(g), 20);
}

// Perfect game = 300 (12 strikes)
{
  const g = createGame();
  rollMany(g, new Array(12).fill(10));
  check("perfect 300", totalScore(g), 300);
}

// One spare then 3 then zeros: spare frame = 10 + 3 = 13, next frame 3, total 16
{
  const g = createGame();
  rollMany(g, [5, 5, 3, 0]);
  rollMany(g, new Array(16).fill(0));
  check("spare bonus", totalScore(g), 16);
}

// One strike then 3 and 4: strike frame = 10+3+4=17, next = 7 => 24
{
  const g = createGame();
  rollMany(g, [10, 3, 4]);
  rollMany(g, new Array(16).fill(0));
  check("strike bonus", totalScore(g), 24);
}

// Classic example game from Wikipedia-style: alternating to a known total.
// 9/ in every frame, then strike fill in 10th: 10 frames of spare-with-9-bonus.
{
  const g = createGame();
  // frames 1-9: 9 then spare(1). 10th: 9, spare, strike fill.
  for (let i = 0; i < 9; i++) rollMany(g, [9, 1]);
  rollMany(g, [9, 1, 10]); // 10th frame: 9 + spare, fill ball strike
  // Each of frames 1-9 = 10 + next first ball (9) = 19 => 171; 10th = 9+1+10=20 => 191
  check("all nines spares", totalScore(g), 190);
}

// 10th frame: strike + strike + strike = 30 added
{
  const g = createGame();
  rollMany(g, new Array(18).fill(0)); // 9 open frames of 0,0
  rollMany(g, [10, 10, 10]);
  check("tenth triple strike", totalScore(g), 30);
}

// 10th frame spare then bonus ball
{
  const g = createGame();
  rollMany(g, new Array(18).fill(0));
  rollMany(g, [7, 3, 5]); // spare + 5 bonus
  check("tenth spare bonus", totalScore(g), 15);
}

// Symbols
{
  const g = createGame();
  rollMany(g, [10]); // strike frame 1
  check("symbol strike", rollSymbol(g, 0, 0), "X");
  rollMany(g, [7, 3]); // spare frame 2
  check("symbol spare", rollSymbol(g, 1, 1), "/");
  check("symbol seven", rollSymbol(g, 1, 0), "7");
  rollMany(g, [0]);
  check("symbol gutter", rollSymbol(g, 2, 0), "-");
}

// frameScores: open running totals
{
  const g = createGame();
  rollMany(g, [1, 2, 3, 4]);
  const s = frameScores(g);
  check("running f1", s[0], 3);
  check("running f2", s[1], 10);
  check("f3 null", s[2], null);
}

console.log(`\n${pass} passed, ${fail} failed`);
process.exit(fail ? 1 : 0);

// Physics world (cannon-es). Owns rigid bodies for ball, 10 pins, lane, gutters,
// back wall, and side bumpers. Pure physics — no rendering, no Three.js here.
//
// Coordinate convention (shared with scene.js):
//   +Z points DOWN the lane, from the foul line (z=0) toward the pins (z = LANE_LENGTH).
//   x is across the lane (left/right). y is up.

import * as CANNON from "cannon-es";

// Real-ish ten-pin dimensions, scaled to meters.
export const LANE_LENGTH = 18.3; // ~60 ft
export const LANE_WIDTH = 1.05; // ~41.5 in
export const GUTTER_WIDTH = 0.23;
export const BALL_RADIUS = 0.108; // ~8.5 in diameter
export const BALL_MASS = 6.0; // kg (~13 lb)
export const PIN_HEIGHT = 0.38;
export const PIN_RADIUS = 0.06;
export const PIN_MASS = 1.5; // kg (light vs ball so they scatter)
export const FOUL_LINE_Z = 0;
export const PIN_SPOT_Z = LANE_LENGTH - 0.9; // head pin location
export const PIN_PITCH = 0.305; // 12 in between pin centers (board spacing)

// Standard triangular pin layout, row by row (row 0 = head pin nearest player).
// Offsets are in lane units; we convert to world coords at build time.
const PIN_LAYOUT = [
  [0], // head pin
  [-0.5, 0.5],
  [-1, 0, 1],
  [-1.5, -0.5, 0.5, 1.5],
];

export class PhysicsWorld {
  constructor() {
    this.world = new CANNON.World({ gravity: new CANNON.Vec3(0, -9.82, 0) });
    this.world.broadphase = new CANNON.SAPBroadphase(this.world);
    this.world.allowSleep = true;
    this.world.solver.iterations = 20;
    this.world.defaultContactMaterial.contactEquationStiffness = 1e8;

    this._materials();
    this._lane();
    this._gutters();
    this._walls();

    this.ball = this._makeBall();
    this.pins = this._makePins();
  }

  _materials() {
    this.matLane = new CANNON.Material("lane");
    this.matBall = new CANNON.Material("ball");
    this.matPin = new CANNON.Material("pin");
    this.matGutter = new CANNON.Material("gutter");

    // Ball on lane: low friction, low restitution (oily lane → it slides/rolls).
    this.world.addContactMaterial(
      new CANNON.ContactMaterial(this.matBall, this.matLane, {
        friction: 0.06,
        restitution: 0.02,
      })
    );
    // Ball on pin: pins fly.
    this.world.addContactMaterial(
      new CANNON.ContactMaterial(this.matBall, this.matPin, {
        friction: 0.05,
        restitution: 0.35,
      })
    );
    // Pin on pin: they clatter into each other.
    this.world.addContactMaterial(
      new CANNON.ContactMaterial(this.matPin, this.matPin, {
        friction: 0.1,
        restitution: 0.4,
      })
    );
    // Pin on lane.
    this.world.addContactMaterial(
      new CANNON.ContactMaterial(this.matPin, this.matLane, {
        friction: 0.3,
        restitution: 0.2,
      })
    );
    // Ball in gutter: high friction, ball dies slowly.
    this.world.addContactMaterial(
      new CANNON.ContactMaterial(this.matBall, this.matGutter, {
        friction: 0.4,
        restitution: 0.05,
      })
    );
  }

  _lane() {
    const lane = new CANNON.Body({ mass: 0, material: this.matLane });
    lane.addShape(new CANNON.Plane());
    // Rotate plane to be horizontal (normal +y).
    lane.quaternion.setFromEuler(-Math.PI / 2, 0, 0);
    lane.position.set(0, 0, 0);
    this.world.addBody(lane);
    this.laneBody = lane;
  }

  _gutters() {
    // Two recessed troughs flanking the lane. Modeled as angled floors slightly
    // below lane level so a ball that drifts off falls in and is slowed.
    const half = LANE_WIDTH / 2;
    const gutterY = -0.07;
    const len = LANE_LENGTH;

    const makeGutterFloor = (xCenter) => {
      const body = new CANNON.Body({ mass: 0, material: this.matGutter });
      const shape = new CANNON.Box(
        new CANNON.Vec3(GUTTER_WIDTH / 2, 0.02, len / 2)
      );
      body.addShape(shape);
      body.position.set(xCenter, gutterY, len / 2);
      this.world.addBody(body);
      return body;
    };
    // outer walls of gutters keep the ball contained
    const makeGutterWall = (x) => {
      const body = new CANNON.Body({ mass: 0, material: this.matGutter });
      body.addShape(new CANNON.Box(new CANNON.Vec3(0.03, 0.18, len / 2)));
      body.position.set(x, 0.05, len / 2);
      this.world.addBody(body);
      return body;
    };

    makeGutterFloor(-(half + GUTTER_WIDTH / 2));
    makeGutterFloor(half + GUTTER_WIDTH / 2);
    makeGutterWall(-(half + GUTTER_WIDTH));
    makeGutterWall(half + GUTTER_WIDTH);

    // Low lips between lane and gutter so the ball doesn't trivially bounce back.
    const makeLip = (x) => {
      const body = new CANNON.Body({ mass: 0, material: this.matGutter });
      body.addShape(new CANNON.Box(new CANNON.Vec3(0.005, 0.015, len / 2)));
      body.position.set(x, 0.0, len / 2);
      this.world.addBody(body);
    };
    makeLip(-half);
    makeLip(half);
  }

  _walls() {
    // Back wall behind the pins (pit) — absorbs the ball and pins.
    const back = new CANNON.Body({ mass: 0, material: this.matGutter });
    back.addShape(new CANNON.Box(new CANNON.Vec3(2, 1.2, 0.1)));
    back.position.set(0, 0.6, LANE_LENGTH + 0.6);
    this.world.addBody(back);
    this.backWall = back;

    // Pit floor (lower) so pins fall away after being struck.
    const pit = new CANNON.Body({ mass: 0, material: this.matGutter });
    pit.addShape(new CANNON.Box(new CANNON.Vec3(2, 0.1, 0.9)));
    pit.position.set(0, -0.25, LANE_LENGTH + 0.3);
    this.world.addBody(pit);
  }

  _makeBall() {
    const body = new CANNON.Body({
      mass: BALL_MASS,
      material: this.matBall,
      shape: new CANNON.Sphere(BALL_RADIUS),
      linearDamping: 0.012,
      angularDamping: 0.012,
    });
    body.allowSleep = true;
    body.sleepSpeedLimit = 0.15;
    body.sleepTimeLimit = 0.4;
    this.resetBall();
    this.world.addBody(body);
    return body;
  }

  resetBall(x = 0) {
    const b = this.ball;
    if (!b) return;
    b.velocity.setZero();
    b.angularVelocity.setZero();
    b.force.setZero();
    b.torque.setZero();
    b.position.set(x, BALL_RADIUS, FOUL_LINE_Z + 0.2);
    b.quaternion.set(0, 0, 0, 1);
    b.wakeUp();
  }

  // Launch the ball: speed (m/s) down lane, lateral aim, and spin (curve).
  // aimX: lateral starting x. dirX: small lateral velocity component for angle.
  // spin: angular velocity about y that produces a hook via friction.
  launchBall({ speed, aimX, dirX, spin }) {
    const b = this.ball;
    this.resetBall(aimX);
    b.velocity.set(dirX, 0, speed);
    // Topspin around x-axis makes it roll forward; y-spin creates a hook.
    b.angularVelocity.set(speed / BALL_RADIUS, spin, 0);
    b.wakeUp();
  }

  _makePins() {
    const pins = [];
    let id = 0;
    PIN_LAYOUT.forEach((row, rowIndex) => {
      row.forEach((offset) => {
        const body = new CANNON.Body({
          mass: PIN_MASS,
          material: this.matPin,
          linearDamping: 0.2,
          angularDamping: 0.2,
        });
        // Compound shape: cylinder body approximated by a capsule-ish stack.
        const cyl = new CANNON.Cylinder(
          PIN_RADIUS * 0.7,
          PIN_RADIUS,
          PIN_HEIGHT,
          12
        );
        body.addShape(cyl);
        body.allowSleep = true;
        body.sleepSpeedLimit = 0.1;
        body.sleepTimeLimit = 0.3;
        body._pinId = id++;
        body._home = new CANNON.Vec3(
          offset * PIN_PITCH,
          PIN_HEIGHT / 2,
          PIN_SPOT_Z + rowIndex * PIN_PITCH
        );
        pins.push(body);
        this.world.addBody(body);
      });
    });
    this.resetPins();
    return pins;
  }

  // Place pins upright at their home spots. Optionally only the ones still standing
  // (keepStanding = array of bools) for the second ball of a frame.
  resetPins(keepStanding = null) {
    this.pins.forEach((pin, i) => {
      pin.velocity.setZero();
      pin.angularVelocity.setZero();
      pin.force.setZero();
      pin.torque.setZero();
      if (keepStanding && !keepStanding[i]) {
        // removed pin: park it far below/out of play
        pin.position.set(pin._home.x, -5, pin._home.z);
        pin.sleep();
        return;
      }
      pin.position.copy(pin._home);
      pin.quaternion.set(0, 0, 0, 1);
      pin.wakeUp();
    });
  }

  // A pin counts as knocked down if it's tilted past ~45° or moved off its spot
  // or fell into the pit.
  standingMask() {
    return this.pins.map((pin) => {
      if (pin.position.y < -1) return false; // parked / fell off
      const up = new CANNON.Vec3(0, 1, 0);
      const local = new CANNON.Vec3();
      pin.quaternion.vmult(up, local);
      const tilt = Math.acos(Math.max(-1, Math.min(1, local.y)));
      if (tilt > Math.PI / 4) return false; // toppled
      const dx = pin.position.x - pin._home.x;
      const dz = pin.position.z - pin._home.z;
      const moved = Math.sqrt(dx * dx + dz * dz);
      if (moved > PIN_RADIUS * 1.6) return false; // knocked off spot
      if (pin.position.y < PIN_HEIGHT * 0.3) return false; // lying flat
      return true;
    });
  }

  // True when everything has essentially stopped moving (ball + pins asleep/slow).
  isSettled() {
    const ballSpeed = this.ball.velocity.length();
    const ballPastPins = this.ball.position.z > PIN_SPOT_Z + 0.3;
    const ballInGutter =
      Math.abs(this.ball.position.x) > LANE_WIDTH / 2 + 0.02 &&
      this.ball.position.z > 2;
    const ballSlow = ballSpeed < 0.25;

    let pinsCalm = true;
    for (const pin of this.pins) {
      if (pin.position.y < -1) continue; // parked
      if (pin.velocity.length() > 0.18 || pin.angularVelocity.length() > 0.4) {
        pinsCalm = false;
        break;
      }
    }
    // Settled if pins are calm AND the ball has either stopped, gone past the
    // pins, or is dawdling in the gutter.
    return pinsCalm && (ballSlow || ballPastPins || (ballInGutter && ballSpeed < 1.2));
  }

  step(dt) {
    this.world.step(1 / 120, dt, 4);
  }
}

// Three.js scene: lane, gutters, pins, ball, lighting, environment, camera.
// Reads body transforms from the physics world each frame and syncs meshes.

import * as THREE from "three";
import {
  LANE_LENGTH,
  LANE_WIDTH,
  GUTTER_WIDTH,
  BALL_RADIUS,
  PIN_HEIGHT,
  PIN_RADIUS,
  PIN_SPOT_Z,
} from "./physics.js";

export class BowlingScene {
  constructor(canvas) {
    this.renderer = new THREE.WebGLRenderer({
      canvas,
      antialias: true,
      alpha: false,
    });
    this.renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    this.renderer.shadowMap.enabled = true;
    this.renderer.shadowMap.type = THREE.PCFSoftShadowMap;
    this.renderer.outputColorSpace = THREE.SRGBColorSpace;
    this.renderer.toneMapping = THREE.ACESFilmicToneMapping;
    this.renderer.toneMappingExposure = 1.05;

    this.scene = new THREE.Scene();
    this.scene.background = new THREE.Color(0x0a0d18);
    this.scene.fog = new THREE.Fog(0x0a0d18, 22, 40);

    this.camera = new THREE.PerspectiveCamera(55, 1, 0.05, 200);
    this.cameraTarget = new THREE.Vector3(0, 0.4, PIN_SPOT_Z);

    this._lights();
    this._lane();
    this._gutters();
    this._environment();
    this.ballMesh = this._ball();
    this.pinMeshes = [];
    this.aimArrow = this._aimArrow();
    this.powerArc = this._powerArc();

    this.resize();
  }

  _lights() {
    const amb = new THREE.AmbientLight(0x404a66, 1.4);
    this.scene.add(amb);

    const hemi = new THREE.HemisphereLight(0x8severe, 0x202028, 0.0);
    // (hemisphere color typo guard) recreate cleanly:
    this.scene.remove(hemi);
    const hemi2 = new THREE.HemisphereLight(0x88aaff, 0x202028, 0.5);
    this.scene.add(hemi2);

    // Key light over the pins (like the pin-deck spotlight).
    const key = new THREE.DirectionalLight(0xfff2d8, 2.0);
    key.position.set(2.5, 9, PIN_SPOT_Z - 2);
    key.castShadow = true;
    key.shadow.mapSize.set(2048, 2048);
    key.shadow.camera.near = 1;
    key.shadow.camera.far = 40;
    const s = 12;
    key.shadow.camera.left = -s;
    key.shadow.camera.right = s;
    key.shadow.camera.top = s;
    key.shadow.camera.bottom = -s;
    key.shadow.bias = -0.0004;
    this.scene.add(key);
    this.scene.add(key.target);
    key.target.position.set(0, 0, PIN_SPOT_Z);

    // Fill light near the player.
    const fill = new THREE.DirectionalLight(0x9db4ff, 0.6);
    fill.position.set(-3, 5, -4);
    this.scene.add(fill);

    // Pin-deck accent spotlight.
    const spot = new THREE.SpotLight(0xffffff, 30, 14, Math.PI / 7, 0.4, 1.5);
    spot.position.set(0, 6, PIN_SPOT_Z + 0.5);
    spot.target.position.set(0, 0, PIN_SPOT_Z + 0.8);
    spot.castShadow = true;
    spot.shadow.mapSize.set(1024, 1024);
    this.scene.add(spot);
    this.scene.add(spot.target);
  }

  _woodTexture() {
    // Procedural wood-plank lane texture on a canvas.
    const c = document.createElement("canvas");
    c.width = 256;
    c.height = 2048;
    const ctx = c.getContext("2d");
    const grd = ctx.createLinearGradient(0, 0, c.width, 0);
    grd.addColorStop(0, "#c9974f");
    grd.addColorStop(0.5, "#e3b873");
    grd.addColorStop(1, "#c9974f");
    ctx.fillStyle = grd;
    ctx.fillRect(0, 0, c.width, c.height);

    // Plank seams down the lane.
    const planks = 12;
    ctx.strokeStyle = "rgba(80,50,20,0.5)";
    ctx.lineWidth = 2;
    for (let i = 1; i < planks; i++) {
      const x = (c.width / planks) * i;
      ctx.beginPath();
      ctx.moveTo(x, 0);
      ctx.lineTo(x, c.height);
      ctx.stroke();
    }
    // Subtle grain noise.
    for (let i = 0; i < 9000; i++) {
      const x = Math.random() * c.width;
      const y = Math.random() * c.height;
      ctx.fillStyle = `rgba(90,55,25,${Math.random() * 0.06})`;
      ctx.fillRect(x, y, 1, Math.random() * 18);
    }
    const tex = new THREE.CanvasTexture(c);
    tex.colorSpace = THREE.SRGBColorSpace;
    tex.wrapS = tex.wrapT = THREE.ClampToEdgeWrapping;
    tex.anisotropy = this.renderer.capabilities.getMaxAnisotropy();
    return tex;
  }

  _lane() {
    const tex = this._woodTexture();
    const mat = new THREE.MeshStandardMaterial({
      map: tex,
      roughness: 0.25,
      metalness: 0.0,
      envMapIntensity: 0.6,
    });
    const geo = new THREE.BoxGeometry(LANE_WIDTH, 0.1, LANE_LENGTH);
    const lane = new THREE.Mesh(geo, mat);
    lane.position.set(0, -0.05, LANE_LENGTH / 2);
    lane.receiveShadow = true;
    this.scene.add(lane);

    // Foul line.
    const foulGeo = new THREE.BoxGeometry(LANE_WIDTH, 0.012, 0.03);
    const foul = new THREE.Mesh(
      foulGeo,
      new THREE.MeshStandardMaterial({ color: 0x111111, roughness: 0.6 })
    );
    foul.position.set(0, 0.001, 0.05);
    this.scene.add(foul);

    // Aiming arrows (the classic 7 dovetail arrows ~ 4.5m down lane).
    const arrowMat = new THREE.MeshStandardMaterial({
      color: 0x5a3a18,
      roughness: 0.5,
    });
    const arrowXs = [-0.38, -0.25, -0.12, 0, 0.12, 0.25, 0.38];
    arrowXs.forEach((x, i) => {
      const depth = 4.2 + Math.abs(x) * 2.2;
      const a = new THREE.Mesh(new THREE.ConeGeometry(0.03, 0.12, 4), arrowMat);
      a.rotation.x = -Math.PI / 2;
      a.rotation.z = Math.PI / 4;
      a.position.set(x, 0.006, depth);
      this.scene.add(a);
    });

    // Approach area (darker) behind the foul line where the player stands.
    const approach = new THREE.Mesh(
      new THREE.BoxGeometry(LANE_WIDTH + GUTTER_WIDTH * 2 + 0.3, 0.1, 3),
      new THREE.MeshStandardMaterial({ color: 0x3a2c1a, roughness: 0.5 })
    );
    approach.position.set(0, -0.051, -1.5);
    approach.receiveShadow = true;
    this.scene.add(approach);
  }

  _gutters() {
    const half = LANE_WIDTH / 2;
    const gutterMat = new THREE.MeshStandardMaterial({
      color: 0x14181f,
      roughness: 0.3,
      metalness: 0.5,
    });
    [-(half + GUTTER_WIDTH / 2), half + GUTTER_WIDTH / 2].forEach((x) => {
      const g = new THREE.Mesh(
        new THREE.BoxGeometry(GUTTER_WIDTH, 0.12, LANE_LENGTH),
        gutterMat
      );
      g.position.set(x, -0.09, LANE_LENGTH / 2);
      g.receiveShadow = true;
      this.scene.add(g);
    });
  }

  _environment() {
    // Pin deck (slightly raised platform under the pins).
    const deck = new THREE.Mesh(
      new THREE.BoxGeometry(LANE_WIDTH + 0.2, 0.06, 1.6),
      new THREE.MeshStandardMaterial({ color: 0xece2c8, roughness: 0.4 })
    );
    deck.position.set(0, -0.03, PIN_SPOT_Z + 0.45);
    deck.receiveShadow = true;
    this.scene.add(deck);

    // Pit / back wall with a backdrop.
    const back = new THREE.Mesh(
      new THREE.BoxGeometry(4, 2.4, 0.2),
      new THREE.MeshStandardMaterial({ color: 0x161a26, roughness: 0.8 })
    );
    back.position.set(0, 1.0, LANE_LENGTH + 0.7);
    back.receiveShadow = true;
    this.scene.add(back);

    // Glowing logo strip on the back wall.
    const strip = new THREE.Mesh(
      new THREE.PlaneGeometry(2.6, 0.5),
      new THREE.MeshBasicMaterial({ color: 0x2b6cff })
    );
    strip.position.set(0, 1.5, LANE_LENGTH + 0.59);
    this.scene.add(strip);

    // Side walls for enclosure.
    const wallMat = new THREE.MeshStandardMaterial({
      color: 0x0f1320,
      roughness: 0.9,
    });
    [-1.6, 1.6].forEach((x) => {
      const w = new THREE.Mesh(
        new THREE.BoxGeometry(0.2, 3, LANE_LENGTH + 4),
        wallMat
      );
      w.position.set(x, 1.2, LANE_LENGTH / 2);
      this.scene.add(w);
    });

    // Ceiling.
    const ceil = new THREE.Mesh(
      new THREE.BoxGeometry(4, 0.2, LANE_LENGTH + 4),
      new THREE.MeshStandardMaterial({ color: 0x0c1018, roughness: 1 })
    );
    ceil.position.set(0, 3.2, LANE_LENGTH / 2);
    this.scene.add(ceil);
  }

  _ball() {
    const geo = new THREE.SphereGeometry(BALL_RADIUS, 48, 48);
    const mat = new THREE.MeshPhysicalMaterial({
      color: 0x1f6fff,
      roughness: 0.12,
      metalness: 0.1,
      clearcoat: 1.0,
      clearcoatRoughness: 0.06,
      envMapIntensity: 1.0,
    });
    const mesh = new THREE.Mesh(geo, mat);
    mesh.castShadow = true;
    this.scene.add(mesh);

    // Finger holes (three small dark dots) as a child group so they rotate with ball.
    const holeMat = new THREE.MeshStandardMaterial({
      color: 0x0a0a0a,
      roughness: 0.8,
    });
    const holes = new THREE.Group();
    const positions = [
      [0.02, 0.9, 0.03],
      [-0.02, 0.92, 0.02],
      [0, 0.9, -0.03],
    ];
    positions.forEach(([hx, hy, hz]) => {
      const h = new THREE.Mesh(
        new THREE.CircleGeometry(BALL_RADIUS * 0.14, 16),
        holeMat
      );
      const dir = new THREE.Vector3(hx, hy, hz).normalize();
      h.position.copy(dir.multiplyScalar(BALL_RADIUS * 0.99));
      h.lookAt(0, 0, 0);
      h.position.multiplyScalar(-1);
      h.position.copy(dir.multiplyScalar(BALL_RADIUS * 0.99));
      h.lookAt(dir.clone().multiplyScalar(2));
      holes.add(h);
    });
    mesh.add(holes);
    return mesh;
  }

  setBallColor(hex) {
    this.ballMesh.material.color.setHex(hex);
  }

  // Build pin meshes once the physics pins are known.
  buildPins(pinBodies) {
    this.pinMeshes.forEach((m) => this.scene.remove(m));
    this.pinMeshes = pinBodies.map(() => this._pinMesh());
    this.pinMeshes.forEach((m) => this.scene.add(m));
  }

  _pinMesh() {
    const group = new THREE.Group();
    // Bowling-pin silhouette via a lathe.
    const profile = [];
    const pts = [
      [0.0, 0.0],
      [0.34, 0.02],
      [0.42, 0.06],
      [0.5, 0.16],
      [0.46, 0.3],
      [0.34, 0.42],
      [0.28, 0.5],
      [0.3, 0.62],
      [0.42, 0.72],
      [0.46, 0.82],
      [0.4, 0.92],
      [0.3, 0.98],
      [0.22, 1.0],
      [0.0, 1.0],
    ];
    pts.forEach(([r, h]) => {
      profile.push(new THREE.Vector2(r * PIN_RADIUS * 2.0, h * PIN_HEIGHT));
    });
    const geo = new THREE.LatheGeometry(profile, 24);
    geo.translate(0, -PIN_HEIGHT / 2, 0); // center of mass at origin to match physics
    const mat = new THREE.MeshStandardMaterial({
      color: 0xfafafa,
      roughness: 0.25,
      metalness: 0.0,
    });
    const body = new THREE.Mesh(geo, mat);
    body.castShadow = true;
    body.receiveShadow = true;
    group.add(body);

    // Red neck stripes.
    const stripeMat = new THREE.MeshStandardMaterial({
      color: 0xd61f2b,
      roughness: 0.3,
    });
    [0.66, 0.74].forEach((h) => {
      const ring = new THREE.Mesh(
        new THREE.CylinderGeometry(
          PIN_RADIUS * 0.62,
          PIN_RADIUS * 0.66,
          PIN_HEIGHT * 0.03,
          24,
          1,
          true
        ),
        stripeMat
      );
      ring.position.y = -PIN_HEIGHT / 2 + h * PIN_HEIGHT;
      group.add(ring);
    });
    return group;
  }

  _aimArrow() {
    const group = new THREE.Group();
    const mat = new THREE.MeshBasicMaterial({
      color: 0x6cf0ff,
      transparent: true,
      opacity: 0.85,
    });
    const shaft = new THREE.Mesh(new THREE.BoxGeometry(0.02, 0.005, 1.6), mat);
    shaft.position.z = 0.8;
    group.add(shaft);
    const head = new THREE.Mesh(new THREE.ConeGeometry(0.06, 0.16, 16), mat);
    head.rotation.x = Math.PI / 2;
    head.position.z = 1.65;
    group.add(head);
    group.visible = false;
    this.scene.add(group);
    return group;
  }

  _powerArc() {
    // A small ground ring under the ball that fills with power color.
    const mat = new THREE.MeshBasicMaterial({
      color: 0xffcc33,
      transparent: true,
      opacity: 0.0,
      side: THREE.DoubleSide,
    });
    const ring = new THREE.Mesh(new THREE.RingGeometry(0.16, 0.22, 32), mat);
    ring.rotation.x = -Math.PI / 2;
    ring.visible = false;
    this.scene.add(ring);
    return ring;
  }

  showAim(x, angleRad, power) {
    this.aimArrow.visible = true;
    this.aimArrow.position.set(x, 0.02, 0.25);
    this.aimArrow.rotation.y = -angleRad;
    const len = 0.4 + power * 1.4;
    this.aimArrow.scale.set(1, 1, len);
    // power ring
    this.powerArc.visible = true;
    this.powerArc.position.set(x, 0.015, 0.2);
    this.powerArc.material.opacity = 0.3 + power * 0.6;
    const g = Math.floor(0xcc * (1 - power) + 0x33 * power);
    this.powerArc.material.color.setRGB(1, g / 255, 0.2);
  }

  hideAim() {
    this.aimArrow.visible = false;
    this.powerArc.visible = false;
  }

  syncBall(body) {
    this.ballMesh.position.copy(body.position);
    this.ballMesh.quaternion.copy(body.quaternion);
  }

  syncPins(bodies) {
    bodies.forEach((b, i) => {
      const m = this.pinMeshes[i];
      if (!m) return;
      m.position.copy(b.position);
      m.quaternion.copy(b.quaternion);
      m.visible = b.position.y > -1;
    });
  }

  // Camera follows the ball down the lane, then settles on the pins.
  updateCamera(ballBody, mode) {
    const cam = this.camera;
    let desired = new THREE.Vector3();
    let look = new THREE.Vector3();

    if (mode === "follow") {
      const z = Math.min(ballBody.position.z, PIN_SPOT_Z - 1.5);
      desired.set(ballBody.position.x * 0.4, 1.1, z - 3.0);
      look.set(ballBody.position.x * 0.3, 0.3, ballBody.position.z + 3);
    } else if (mode === "pins") {
      desired.set(0, 1.4, PIN_SPOT_Z - 4.2);
      look.set(0, 0.4, PIN_SPOT_Z + 0.5);
    } else {
      // aiming / default behind-the-player view
      desired.set(0, 1.5, -3.2);
      look.set(0, 0.35, PIN_SPOT_Z * 0.55);
    }

    cam.position.lerp(desired, 0.06);
    this.cameraTarget.lerp(look, 0.08);
    cam.lookAt(this.cameraTarget);
  }

  resize() {
    const w = window.innerWidth;
    const h = window.innerHeight;
    this.renderer.setSize(w, h, false);
    this.camera.aspect = w / h;
    this.camera.updateProjectionMatrix();
  }

  render() {
    this.renderer.render(this.scene, this.camera);
  }
}

