input.content:
// Game orchestration: ties physics + scene + scoring + input + HUD together,
// and runs the frame/ball state machine.
//
// States:
//   AIMING   - player aims & charges power with the mouse
//   ROLLING  - ball is in motion, camera follows
//   SETTLING - waiting for pins/ball to stop
//   SCORING  - count pins, update scoreboard, brief pause
//   RESET    - rack/sweep for next ball or frame
//   GAMEOVER - final score shown

import * as THREE from "three";
import { PhysicsWorld, LANE_WIDTH, PIN_SPOT_Z } from "./physics.js";
import { BowlingScene } from "./scene.js";
import {
  createGame,
  roll,
  pinsAvailable,
  frameScores,
  totalScore,
  rollSymbol,
  TOTAL_FRAMES,
} from "./scoring.js";
import { InputController } from "./input.js";

const STATE = {
  AIMING: "AIMING",
  ROLLING: "ROLLING",
  SETTLING: "SETTLING",
  SCORING: "SCORING",
  RESET: "RESET",
  GAMEOVER: "GAMEOVER",
};

const BALL_COLORS = [0x1f6fff, 0xff3b3b, 0x29c46a, 0xb14bff, 0xff8c1a, 0x14d3d3];

export class BowlingGame {
  constructor(canvas, hud) {
    this.physics = new PhysicsWorld();
    this.scene = new BowlingScene(canvas);
    this.scene.buildPins(this.physics.pins);
    this.hud = hud;

    this.scoreGame = createGame();
    this.state = STATE.AIMING;
    this.standingBefore = this.physics.standingMask(); // all true at frame start
    this.settleTimer = 0;
    this.scoreTimer = 0;
    this.clock = new THREE.Clock();
    this.colorIndex = 0;

    this.input = new InputController(canvas, {
      onAimUpdate: (aim) => this._onAimUpdate(aim),
      onRelease: (shot) => this._throw(shot),
      isInteractive: () => this.state === STATE.AIMING,
    });

    window.addEventListener("resize", () => this.scene.resize());

    this._renderScoreboard();
    this._setMessage("Drag back and release to bowl. Aim with left/right.");
    this._loop();
  }

  _onAimUpdate(aim) {
    // aim: { aimX (-1..1), angle (rad), power (0..1), spin (-1..1) }
    const x = aim.aimX * (LANE_WIDTH / 2 - 0.08);
    this.physics.resetBall(x);
    this.scene.syncBall(this.physics.ball);
    this.scene.showAim(x, aim.angle, aim.power);
    this.hud.setPower(aim.power, aim.spin);
  }

  _throw(shot) {
    if (this.state !== STATE.AIMING) return;
    const x = shot.aimX * (LANE_WIDTH / 2 - 0.08);
    const speed = 7 + shot.power * 9; // 7..16 m/s
    const dirX = Math.tan(shot.angle) * speed * 0.6;
    const spin = shot.spin * 14; // hook strength
    this.physics.launchBall({ speed, aimX: x, dirX, spin });
    this.scene.hideAim();
    this.state = STATE.ROLLING;
    this.settleTimer = 0;
    this._setMessage("");
    this.hud.setPower(0, 0);
  }

  _frameNumber() {
    return this.scoreGame.currentFrame + 1;
  }

  _ballNumberInFrame() {
    return this.scoreGame.frames[this.scoreGame.currentFrame].rolls.length + 1;
  }

  _afterSettle() {
    // Count how many of the pins that were standing are now down.
    const standingNow = this.physics.standingMask();
    let knocked = 0;
    for (let i = 0; i < standingNow.length; i++) {
      if (this.standingBefore[i] && !standingNow[i]) knocked++;
    }
    // Clamp to pins available (defensive against physics jitter miscounts).
    const avail = pinsAvailable(this.scoreGame);
    knocked = Math.max(0, Math.min(knocked, avail));

    const before = this.scoreGame.currentFrame;
    const result = roll(this.scoreGame, knocked);
    this._renderScoreboard();

    // Decide what message / animation to show.
    let msg = `${knocked} pin${knocked === 1 ? "" : "s"}`;
    const frameRolls = this.scoreGame.frames[before].rolls;
    if (knocked === 10 && frameRolls.length === 1) msg = "STRIKE!  🎳";
    else if (
      frameRolls.length >= 2 &&
      frameRolls[frameRolls.length - 2] + frameRolls[frameRolls.length - 1] === 10 &&
      frameRolls[frameRolls.length - 2] !== 10
    )
      msg = "SPARE!  ✨";
    else if (knocked === 0) msg = "Gutter / Miss";

    this._setMessage(msg);
    this.scoreTimer = 0;
    this.state = STATE.SCORING;
    this._pendingResult = result;
  }

  _applyResult(result) {
    if (result.type === "gameOver") {
      this.state = STATE.GAMEOVER;
      this.hud.showGameOver(totalScore(this.scoreGame), () => this.restart());
      return;
    }

    if (result.type === "nextBall") {
      // Same frame: sweep fallen pins, leave standing ones, fresh ball.
      const standingNow = this.physics.standingMask();
      // For the 10th frame, a strike/spare on a ball gives a fresh rack.
      const avail = pinsAvailable(this.scoreGame);
      if (avail === 10) {
        this.physics.resetPins(); // fresh rack
      } else {
        this.physics.resetPins(standingNow); // keep standers, remove fallen
      }
      this.standingBefore = this.physics.standingMask();
    } else if (result.type === "nextFrame") {
      this.physics.resetPins(); // fresh full rack
      this.standingBefore = this.physics.standingMask();
      // New ball color each frame for variety.
      this.colorIndex = (this.colorIndex + 1) % BALL_COLORS.length;
      this.scene.setBallColor(BALL_COLORS[this.colorIndex]);
    }

    this.physics.resetBall(0);
    this.scene.syncBall(this.physics.ball);
    this.scene.syncPins(this.physics.pins);
    this.state = STATE.AIMING;
    this.input.reset();
    this._updateTurnLabel();
    this._setMessage("");
  }

  restart() {
    this.scoreGame = createGame();
    this.physics.resetPins();
    this.physics.resetBall(0);
    this.standingBefore = this.physics.standingMask();
    this.colorIndex = 0;
    this.scene.setBallColor(BALL_COLORS[0]);
    this.scene.syncPins(this.physics.pins);
    this.scene.syncBall(this.physics.ball);
    this.state = STATE.AIMING;
    this.input.reset();
    this.hud.hideGameOver();
    this._renderScoreboard();
    this._updateTurnLabel();
    this._setMessage("New game! Drag back and release to bowl.");
  }

  _updateTurnLabel() {
    this.hud.setTurn(this._frameNumber(), this._ballNumberInFrame());
  }

  _setMessage(text) {
    this.hud.setMessage(text);
  }

  _renderScoreboard() {
    const scores = frameScores(this.scoreGame);
    const cells = [];
    for (let f = 0; f < TOTAL_FRAMES; f++) {
      const rolls = this.scoreGame.frames[f].rolls;
      const isTenth = f === TOTAL_FRAMES - 1;
      const symbols = [];
      const slots = isTenth ? 3 : 2;
      for (let r = 0; r < slots; r++) {
        symbols.push(rollSymbol(this.scoreGame, f, r));
      }
      cells.push({
        frame: f + 1,
        symbols,
        score: scores[f],
        active: f === this.scoreGame.currentFrame && !this.scoreGame.over,
      });
    }
    this.hud.renderScoreboard(cells, totalScore(this.scoreGame));
    this._updateTurnLabel();
  }

  _cameraMode() {
    if (this.state === STATE.ROLLING) {
      if (this.physics.ball.position.z > PIN_SPOT_Z - 5) return "pins";
      return "follow";
    }
    if (this.state === STATE.SETTLING || this.state === STATE.SCORING)
      return "pins";
    return "aim";
  }

  _loop = () => {
    const dt = Math.min(this.clock.getDelta(), 0.05);

    if (this.state === STATE.ROLLING || this.state === STATE.SETTLING) {
      this.physics.step(dt);
      this.scene.syncBall(this.physics.ball);
      this.scene.syncPins(this.physics.pins);

      if (this.state === STATE.ROLLING) {
        // Transition to settling once the ball reaches the pins or leaves play.
        if (
          this.physics.ball.position.z > PIN_SPOT_Z - 1.5 ||
          this.physics.ball.position.z > 4 &&
            Math.abs(this.physics.ball.position.x) > LANE_WIDTH / 2 + 0.05
        ) {
          this.state = STATE.SETTLING;
          this.settleTimer = 0;
        }
      } else if (this.state === STATE.SETTLING) {
        this.settleTimer += dt;
        if (this.physics.isSettled() || this.settleTimer > 6) {
          this._afterSettle();
        }
      }
    } else if (this.state === STATE.SCORING) {
      // keep stepping a touch so pins finish toppling visually
      this.physics.step(dt);
      this.scene.syncPins(this.physics.pins);
      this.scoreTimer += dt;
      if (this.scoreTimer > 1.6) {
        this._applyResult(this._pendingResult);
      }
    }

    this.scene.updateCamera(this.physics.ball, this._cameraMode());
    this.scene.render();
    requestAnimationFrame(this._loop);
  };
}

// Mouse input → a bowling shot.
//
// Control scheme (mouse-only, intuitive):
//   • Move the mouse left/right anywhere on screen to AIM (set the ball's lateral
//     start position and a small launch angle).
//   • PRESS and DRAG BACKWARD (downward on screen) to charge POWER — like pulling
//     back a slingshot. The further you pull, the more power.
//   • Drag LEFT/RIGHT while pulling back to add SPIN (hook). Pulling back to the
//     left curves the ball right-to-left, and vice versa.
//   • RELEASE to bowl.
//
// Also supports: just click without dragging = a soft straight roll.

export class InputController {
  constructor(canvas, { onAimUpdate, onRelease, isInteractive }) {
    this.canvas = canvas;
    this.onAimUpdate = onAimUpdate;
    this.onRelease = onRelease;
    this.isInteractive = isInteractive;

    this.dragging = false;
    this.startY = 0;
    this.startX = 0;
    this.aimX = 0; // -1..1 lateral aim
    this.angle = 0; // radians launch angle
    this.power = 0; // 0..1
    this.spin = 0; // -1..1

    this._bind();
    this._emit();
  }

  reset() {
    this.dragging = false;
    this.power = 0;
    this.spin = 0;
    this._emit();
  }

  _bind() {
    const c = this.canvas;
    c.addEventListener("pointermove", (e) => this._onMove(e));
    c.addEventListener("pointerdown", (e) => this._onDown(e));
    window.addEventListener("pointerup", (e) => this._onUp(e));
    window.addEventListener("pointercancel", () => this._cancel());
    // Keyboard fallback for accessibility / no-drag play.
    window.addEventListener("keydown", (e) => this._onKey(e));
  }

  _px(e) {
    const r = this.canvas.getBoundingClientRect();
    return {
      x: (e.clientX - r.left) / r.width, // 0..1
      y: (e.clientY - r.top) / r.height, // 0..1
    };
  }

  _onMove(e) {
    if (!this.isInteractive()) return;
    const p = this._px(e);

    if (!this.dragging) {
      // Free aim: map horizontal cursor position to lateral aim.
      this.aimX = clamp((p.x - 0.5) * 2, -1, 1);
      this.angle = -this.aimX * 0.12; // slight angle toward center
      this._emit();
      return;
    }

    // Dragging back: vertical distance dragged downward = power.
    const dy = p.y - this.startY; // positive = dragged down
    this.power = clamp(dy * 1.8, 0, 1);
    // Horizontal drag during pull = spin.
    const dx = p.x - this.startX;
    this.spin = clamp(dx * -3.0, -1, 1);
    // Keep the aim from the press position; allow fine angle from horizontal too.
    this.angle = -this.aimX * 0.12 + dx * 0.25;
    this._emit();
  }

  _onDown(e) {
    if (!this.isInteractive()) return;
    this.canvas.setPointerCapture?.(e.pointerId);
    const p = this._px(e);
    this.dragging = true;
    this.startY = p.y;
    this.startX = p.x;
    this.aimX = clamp((p.x - 0.5) * 2, -1, 1);
    this.power = 0;
    this.spin = 0;
    this._emit();
  }

  _onUp(e) {
    if (!this.dragging) return;
    this.dragging = false;
    if (!this.isInteractive()) {
      this.power = 0;
      this.spin = 0;
      return;
    }
    // Minimum power so a tiny drag still rolls the ball.
    const power = Math.max(this.power, 0.18);
    this.onRelease({
      aimX: this.aimX,
      angle: this.angle,
      power,
      spin: this.spin,
    });
    this.power = 0;
    this.spin = 0;
  }

  _cancel() {
    this.dragging = false;
    this.power = 0;
    this.spin = 0;
    this._emit();
  }

  _onKey(e) {
    if (!this.isInteractive()) return;
    const step = 0.06;
    if (e.key === "ArrowLeft") {
      this.aimX = clamp(this.aimX - step, -1, 1);
      this._emit();
    } else if (e.key === "ArrowRight") {
      this.aimX = clamp(this.aimX + step, -1, 1);
      this._emit();
    } else if (e.key === " " || e.key === "Enter") {
      e.preventDefault();
      // space bowls with a default medium power.
      this.onRelease({ aimX: this.aimX, angle: this.angle, power: 0.7, spin: this.spin });
    } else if (e.key === "a" || e.key === "A") {
      this.spin = clamp(this.spin - 0.15, -1, 1);
      this._emit();
    } else if (e.key === "d" || e.key === "D") {
      this.spin = clamp(this.spin + 0.15, -1, 1);
      this._emit();
    }
  }

  _emit() {
    this.onAimUpdate({
      aimX: this.aimX,
      angle: this.angle,
      power: this.power,
      spin: this.spin,
    });
  }
}

function clamp(v, lo, hi) {
  return Math.max(lo, Math.min(hi, v));
}

// HUD: scoreboard, power/spin meter, status message, game-over overlay.
// Pure DOM; the game calls these methods.

export class HUD {
  constructor() {
    this.scoreboard = document.getElementById("scoreboard");
    this.message = document.getElementById("message");
    this.turn = document.getElementById("turn");
    this.powerFill = document.getElementById("power-fill");
    this.spinFill = document.getElementById("spin-fill");
    this.gameOver = document.getElementById("gameover");
    this.finalScore = document.getElementById("final-score");
    this.playAgain = document.getElementById("play-again");
    this._buildScaffold();
  }

  _buildScaffold() {
    // Build 10 empty frame cells once.
    this.scoreboard.innerHTML = "";
    this.frameEls = [];
    for (let f = 0; f < 10; f++) {
      const cell = document.createElement("div");
      cell.className = "frame";
      const head = document.createElement("div");
      head.className = "frame-num";
      head.textContent = String(f + 1);
      const rolls = document.createElement("div");
      rolls.className = "rolls";
      const tenth = f === 9;
      const slots = tenth ? 3 : 2;
      const slotEls = [];
      for (let s = 0; s < slots; s++) {
        const sl = document.createElement("span");
        sl.className = "roll";
        rolls.appendChild(sl);
        slotEls.push(sl);
      }
      const total = document.createElement("div");
      total.className = "frame-total";
      cell.appendChild(head);
      cell.appendChild(rolls);
      cell.appendChild(total);
      this.scoreboard.appendChild(cell);
      this.frameEls.push({ cell, slotEls, total });
    }
  }

  renderScoreboard(cells, grandTotal) {
    cells.forEach((c, i) => {
      const el = this.frameEls[i];
      el.cell.classList.toggle("active", c.active);
      el.slotEls.forEach((slot, s) => {
        const sym = c.symbols[s] ?? "";
        slot.textContent = sym;
        slot.classList.toggle("strike", sym === "X");
        slot.classList.toggle("spare", sym === "/");
      });
      el.total.textContent = c.score == null ? "" : String(c.score);
    });
    const totalEl = document.getElementById("grand-total");
    if (totalEl) totalEl.textContent = String(grandTotal);
  }

  setTurn(frame, ball) {
    this.turn.textContent = `Frame ${frame} · Ball ${ball}`;
  }

  setMessage(text) {
    this.message.textContent = text || "";
    this.message.classList.toggle("show", !!text);
  }

  setPower(power, spin) {
    this.powerFill.style.width = `${Math.round(power * 100)}%`;
    // spin from -1..1 → center-origin bar
    const pct = (spin + 1) / 2; // 0..1
    this.spinFill.style.left = `${pct * 100}%`;
  }

  showGameOver(score, onPlayAgain) {
    this.finalScore.textContent = String(score);
    this.gameOver.classList.add("show");
    this.playAgain.onclick = () => onPlayAgain();
  }

  hideGameOver() {
    this.gameOver.classList.remove("show");
  }
}

// Entry point: wire up HUD + game on the canvas.
import { BowlingGame } from "./game.js";
import { HUD } from "./hud.js";

function start() {
  const canvas = document.getElementById("game");
  const hud = new HUD();
  // Expose for debugging in the console.
  window.__bowling = new BowlingGame(canvas, hud);

  // Dismiss the intro overlay on first interaction.
  const intro = document.getElementById("intro");
  const dismiss = () => intro.classList.add("hidden");
  document.getElementById("start-btn").addEventListener("click", dismiss);
}

if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", start);
} else {
  start();
}

:root {
  --bg: #070a12;
  --panel: rgba(14, 18, 30, 0.82);
  --panel-border: rgba(120, 160, 255, 0.22);
  --accent: #6cf0ff;
  --accent2: #ffcc33;
  --text: #e8eefc;
  --muted: #93a3c4;
  --strike: #ff5a5a;
  --spare: #58d6ff;
}

* {
  box-sizing: border-box;
  margin: 0;
  padding: 0;
}

html,
body {
  height: 100%;
  overflow: hidden;
  background: var(--bg);
  color: var(--text);
  font-family: "Segoe UI", system-ui, -apple-system, sans-serif;
  user-select: none;
  -webkit-user-select: none;
}

#game {
  position: fixed;
  inset: 0;
  width: 100vw;
  height: 100vh;
  display: block;
  cursor: grab;
  touch-action: none;
}
#game:active {
  cursor: grabbing;
}

/* ---------- Scoreboard (top) ---------- */
#scoreboard-wrap {
  position: fixed;
  top: 12px;
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  align-items: stretch;
  gap: 8px;
  z-index: 10;
}

#scoreboard {
  display: flex;
  gap: 2px;
  background: var(--panel);
  border: 1px solid var(--panel-border);
  border-radius: 12px;
  padding: 6px;
  backdrop-filter: blur(10px);
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.5);
}

.frame {
  display: flex;
  flex-direction: column;
  align-items: stretch;
  min-width: 46px;
  border-radius: 6px;
  overflow: hidden;
  transition: background 0.2s;
}
.frame:last-child {
  min-width: 64px;
}
.frame.active {
  background: rgba(108, 240, 255, 0.14);
  box-shadow: inset 0 0 0 1px var(--accent);
}

.frame-num {
  font-size: 10px;
  color: var(--muted);
  text-align: center;
  padding: 2px 0 0;
  letter-spacing: 0.5px;
}

.rolls {
  display: flex;
  justify-content: flex-end;
  gap: 2px;
  height: 20px;
  padding: 0 3px;
}
.roll {
  width: 18px;
  height: 18px;
  display: grid;
  place-items: center;
  font-size: 13px;
  font-weight: 700;
  border: 1px solid rgba(255, 255, 255, 0.08);
  border-radius: 4px;
  background: rgba(255, 255, 255, 0.03);
}
.roll.strike {
  color: var(--strike);
  border-color: rgba(255, 90, 90, 0.5);
}
.roll.spare {
  color: var(--spare);
  border-color: rgba(88, 214, 255, 0.5);
}

.frame-total {
  text-align: center;
  font-size: 15px;
  font-weight: 800;
  padding: 3px 0 4px;
  min-height: 22px;
}

#grand-total-box {
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  background: var(--panel);
  border: 1px solid var(--panel-border);
  border-radius: 12px;
  padding: 6px 16px;
  backdrop-filter: blur(10px);
}
#grand-total-box .label {
  font-size: 10px;
  color: var(--muted);
  letter-spacing: 1px;
}
#grand-total {
  font-size: 30px;
  font-weight: 900;
  color: var(--accent);
  line-height: 1;
}

/* ---------- Turn + message ---------- */
#turn {
  position: fixed;
  top: 16px;
  left: 16px;
  z-index: 10;
  background: var(--panel);
  border: 1px solid var(--panel-border);
  padding: 8px 14px;
  border-radius: 10px;
  font-size: 14px;
  font-weight: 600;
  backdrop-filter: blur(10px);
}

#message {
  position: fixed;
  top: 38%;
  left: 50%;
  transform: translate(-50%, -50%) scale(0.9);
  z-index: 10;
  font-size: clamp(28px, 6vw, 64px);
  font-weight: 900;
  letter-spacing: 1px;
  text-shadow: 0 4px 24px rgba(0, 0, 0, 0.8), 0 0 30px rgba(108, 240, 255, 0.4);
  opacity: 0;
  pointer-events: none;
  transition: opacity 0.25s, transform 0.25s;
  text-align: center;
}
#message.show {
  opacity: 1;
  transform: translate(-50%, -50%) scale(1);
}

/* ---------- Power / spin meters (bottom) ---------- */
#meters {
  position: fixed;
  bottom: 18px;
  left: 50%;
  transform: translateX(-50%);
  z-index: 10;
  width: min(440px, 86vw);
  display: flex;
  flex-direction: column;
  gap: 8px;
  background: var(--panel);
  border: 1px solid var(--panel-border);
  border-radius: 14px;
  padding: 12px 16px;
  backdrop-filter: blur(10px);
}
.meter-row {
  display: flex;
  align-items: center;
  gap: 10px;
}
.meter-label {
  font-size: 11px;
  color: var(--muted);
  width: 46px;
  letter-spacing: 1px;
}
.bar {
  position: relative;
  flex: 1;
  height: 12px;
  border-radius: 8px;
  background: rgba(255, 255, 255, 0.07);
  overflow: hidden;
}
#power-fill {
  position: absolute;
  inset: 0 auto 0 0;
  width: 0%;
  background: linear-gradient(90deg, #ffe066, #ff7a1a, #ff2d2d);
  transition: width 0.04s linear;
}
.bar.spin {
  overflow: visible;
}
#spin-fill {
  position: absolute;
  top: -3px;
  left: 50%;
  width: 14px;
  height: 18px;
  margin-left: -7px;
  border-radius: 4px;
  background: var(--accent);
  box-shadow: 0 0 10px var(--accent);
  transition: left 0.05s linear;
}
.spin-center {
  position: absolute;
  top: 0;
  left: 50%;
  width: 1px;
  height: 100%;
  background: rgba(255, 255, 255, 0.25);
}

#hint {
  text-align: center;
  font-size: 11px;
  color: var(--muted);
  margin-top: 2px;
}

/* ---------- Intro overlay ---------- */
.overlay {
  position: fixed;
  inset: 0;
  z-index: 50;
  display: grid;
  place-items: center;
  background: radial-gradient(
    ellipse at center,
    rgba(10, 14, 26, 0.82),
    rgba(4, 6, 12, 0.96)
  );
  backdrop-filter: blur(6px);
  transition: opacity 0.4s;
}
.overlay.hidden {
  opacity: 0;
  pointer-events: none;
}
.card {
  background: var(--panel);
  border: 1px solid var(--panel-border);
  border-radius: 20px;
  padding: 34px 40px;
  text-align: center;
  max-width: 460px;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.6);
}
.card h1 {
  font-size: 40px;
  font-weight: 900;
  margin-bottom: 6px;
  background: linear-gradient(90deg, var(--accent), #2b6cff);
  -webkit-background-clip: text;
  background-clip: text;
  color: transparent;
}
.card .sub {
  color: var(--muted);
  margin-bottom: 20px;
  font-size: 15px;
}
.card ul {
  text-align: left;
  list-style: none;
  margin: 0 auto 22px;
  display: grid;
  gap: 10px;
  max-width: 360px;
}
.card li {
  display: flex;
  gap: 10px;
  align-items: flex-start;
  font-size: 14px;
  line-height: 1.4;
}
.card li b {
  color: var(--accent);
}
.kbd {
  display: inline-block;
  padding: 1px 7px;
  border-radius: 5px;
  background: rgba(255, 255, 255, 0.08);
  border: 1px solid rgba(255, 255, 255, 0.15);
  font-family: monospace;
  font-size: 12px;
}
.btn {
  display: inline-block;
  padding: 13px 34px;
  border: none;
  border-radius: 12px;
  font-size: 17px;
  font-weight: 800;
  letter-spacing: 0.5px;
  cursor: pointer;
  color: #06121f;
  background: linear-gradient(90deg, var(--accent), #2b9cff);
  box-shadow: 0 8px 24px rgba(43, 156, 255, 0.4);
  transition: transform 0.12s, box-shadow 0.12s;
}
.btn:hover {
  transform: translateY(-2px);
  box-shadow: 0 12px 30px rgba(43, 156, 255, 0.55);
}
.btn:active {
  transform: translateY(0);
}

/* ---------- Game over ---------- */
#gameover {
  opacity: 0;
  pointer-events: none;
}
#gameover.show {
  opacity: 1;
  pointer-events: auto;
}
#final-score {
  font-size: 80px;
  font-weight: 900;
  color: var(--accent2);
  line-height: 1;
  margin: 10px 0 4px;
  text-shadow: 0 0 40px rgba(255, 204, 51, 0.5);
}

@media (max-width: 560px) {
  .frame {
    min-width: 34px;
  }
  .roll {
    width: 14px;
    height: 14px;
    font-size: 10px;
  }
  #grand-total {
    font-size: 22px;
  }
  #turn {
    font-size: 12px;
    padding: 6px 10px;
  }
}

import puppeteer from "puppeteer-core";

const CHROME = "/Applications/Google Chrome.app/Contents/MacOS/Google Chrome";
const URL = "http://127.0.0.1:8731/index.html";

const browser = await puppeteer.launch({
  executablePath: CHROME,
  headless: "new",
  args: ["--no-sandbox", "--use-gl=angle", "--use-angle=swiftshader", "--enable-webgl", "--ignore-gpu-blocklist"],
});

const page = await browser.newPage();
await page.setViewport({ width: 1280, height: 800 });

const errors = [];
const logs = [];
page.on("console", (m) => logs.push(`[${m.type()}] ${m.text()}`));
page.on("pageerror", (e) => errors.push("PAGEERROR: " + e.message));
page.on("requestfailed", (r) => errors.push("REQFAIL: " + r.url() + " " + r.failure()?.errorText));

await page.goto(URL, { waitUntil: "networkidle2", timeout: 30000 });

// Give modules time to load from CDN and init.
await new Promise((r) => setTimeout(r, 3500));

// Did the game object initialize?
const initState = await page.evaluate(() => {
  const g = window.__bowling;
  if (!g) return { ok: false, reason: "no __bowling" };
  return {
    ok: true,
    state: g.state,
    pinMeshes: g.scene.pinMeshes.length,
    pinBodies: g.physics.pins.length,
    frame: g.scoreGame.currentFrame,
    ballY: +g.physics.ball.position.y.toFixed(3),
  };
});
console.log("INIT:", JSON.stringify(initState));

// Simulate a throw straight down the middle with high power, then run sim.
const throwResult = await page.evaluate(async () => {
  const g = window.__bowling;
  // Directly invoke the throw to avoid pointer-timing flakiness.
  g._throw({ aimX: 0, angle: 0, power: 0.9, spin: 0.05 });
  return { state: g.state, ballZ: +g.physics.ball.position.z.toFixed(2), vel: +g.physics.ball.velocity.length().toFixed(2) };
});
console.log("THROW:", JSON.stringify(throwResult));

// Let physics + state machine run to completion of the ball.
let settled = null;
for (let i = 0; i < 80; i++) {
  await new Promise((r) => setTimeout(r, 150));
  const s = await page.evaluate(() => {
    const g = window.__bowling;
    return {
      state: g.state,
      ballZ: +g.physics.ball.position.z.toFixed(2),
      standing: g.physics.standingMask().filter(Boolean).length,
      frame: g.scoreGame.currentFrame,
      ball: g.scoreGame.frames[0].rolls.slice(),
      total: (() => { try { return g.scoreGame.frames[0].rolls; } catch { return null; } })(),
    };
  });
  if (s.state === "AIMING" && s.frame >= 0 && s.ball.length > 0) {
    settled = s;
    break;
  }
  if (i % 10 === 0) console.log(`  t=${(i*0.15).toFixed(1)}s state=${s.state} ballZ=${s.ballZ} standing=${s.standing}`);
}
console.log("AFTER BALL:", JSON.stringify(settled));

// Final score readout from the engine.
const score = await page.evaluate(() => {
  const g = window.__bowling;
  return {
    rollsFrame1: g.scoreGame.frames[0].rolls,
    currentFrame: g.scoreGame.currentFrame,
  };
});
console.log("SCORE STATE:", JSON.stringify(score));

console.log("\n--- PAGE ERRORS (" + errors.length + ") ---");
errors.forEach((e) => console.log(e));
console.log("\n--- CONSOLE LOGS (last 20) ---");
logs.slice(-20).forEach((l) => console.log(l));

await page.screenshot({ path: "/tmp/bowling_shot.png" });
console.log("\nscreenshot -> /tmp/bowling_shot.png");

await browser.close();
process.exit(errors.length ? 2 : 0);

